import React, { useEffect, useMemo, useState } from "react";
import axios from "axios";
import { useNavigate, useParams } from "react-router-dom";
import { Bus } from "../components/BusCard";

const API_BASE = "http://localhost:5000/api";

const SeatSelection: React.FC = () => {
  const { busId } = useParams();
  const navigate = useNavigate();

  const [bus, setBus] = useState<Bus | null>(null);
  const [selectedSeats, setSelectedSeats] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);
  const [booking, setBooking] = useState(false);

  useEffect(() => {
    const fetchBus = async () => {
      try {
        const response = await axios.get<Bus>(`${API_BASE}/buses/${busId}`);
        setBus(response.data);
      } catch (error) {
        console.error("Failed to fetch bus", error);
      } finally {
        setLoading(false);
      }
    };

    if (busId) {
      fetchBus();
    }
  }, [busId]);

  const totalPrice = useMemo(() => {
    if (!bus) return 0;
    return selectedSeats.length * bus.price;
  }, [selectedSeats, bus]);

  const toggleSeat = (seatNumber: string, isAvailable: boolean) => {
    if (!isAvailable) return;

    setSelectedSeats((prev) =>
      prev.includes(seatNumber) ? prev.filter((s) => s !== seatNumber) : [...prev, seatNumber]
    );
  };

  const handleBooking = async () => {
    if (!bus || !busId || selectedSeats.length === 0) return;

    setBooking(true);
    try {
      const passengerDetails = selectedSeats.map((seat, idx) => ({
        name: `Passenger ${idx + 1}`,
        age: 25,
        gender: "Not Specified",
        seat
      }));

      const response = await axios.post(`${API_BASE}/bookings`, {
        busId,
        seats: selectedSeats,
        passengerDetails
      });

      navigate("/confirmation", {
        state: {
          booking: response.data.booking,
          busName: bus.name
        }
      });
    } catch (error) {
      console.error("Booking failed", error);
      alert("Booking failed. Please try again.");
    } finally {
      setBooking(false);
    }
  };

  if (loading) return <div className="page-container">Loading seats...</div>;
  if (!bus) return <div className="page-container">Bus not found.</div>;

  return (
    <div className="page-container">
      <h2>Select Seats - {bus.name}</h2>
      <p>Price per seat: INR {bus.price}</p>

      <div className="seat-grid">
        {bus.seats.map((seat) => {
          const isSelected = selectedSeats.includes(seat.seatNumber);
          const className = !seat.isAvailable
            ? "seat unavailable"
            : isSelected
            ? "seat selected"
            : "seat";

          return (
            <button
              key={seat.seatNumber}
              className={className}
              onClick={() => toggleSeat(seat.seatNumber, seat.isAvailable)}
              type="button"
            >
              {seat.seatNumber}
            </button>
          );
        })}
      </div>

      <div className="card">
        <p>Selected Seats: {selectedSeats.join(", ") || "None"}</p>
        <p>Total Price: INR {totalPrice}</p>
        <button onClick={handleBooking} disabled={booking || selectedSeats.length === 0}>
          {booking ? "Booking..." : "Confirm Booking"}
        </button>
      </div>
    </div>
  );
};

export default SeatSelection;
